import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { useNavigate } from 'react-router-dom';
import Table from '../Table';
import './style.css';

const POSTS_COLUMNS = [
  { accessor: 'id', Header: 'ID' },
  { accessor: 'title', Header: 'Title' },
  { accessor: 'tag', Header: 'Tag' },
  { accessor: 'body', Header: 'Body' },
  { accessor: 'action', Header: 'Action' },
];

export default function PostsPage() {
  const navigate = useNavigate();
  const [posts, setPosts] = useState([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    setIsLoading(true);

    fetch('https://jsonplaceholder.typicode.com/posts?_limit=12')
      .then((response) => response.json())
      .then((data) => {
        setPosts(data);
        setIsLoading(false);
      })
      .catch(() => {
        setPosts([]);
        setIsLoading(false);
      });
  }, []);

  const tableData = posts.map((post) => ({
    id: post.id,
    title: post.title,
    tag: `User ${post.userId}`,
    body: `${post.body.slice(0, 70)}...`,
    action: (
      <Link
        to={`/posts/${post.id}`}
        className="posts-inline-link"
        onClick={(event) => event.stopPropagation()}
      >
        Read More
      </Link>
    ),
  }));

  return (
    <main className="posts-page">
      <section className="posts-hero">
        <div className="posts-copy">
          <p className="posts-kicker">Posts</p>
          <h1>Read and browse API-powered content.</h1>
          <p>
            This page loads posts from a live API and displays them in a cleaner reusable table.
          </p>
        </div>
        <div className="posts-stats">
          <div className="posts-stat">
            <strong>{isLoading ? '--' : posts.length}</strong>
            <span>Loaded Posts</span>
          </div>
          <div className="posts-stat">
            <strong>API</strong>
            <span>jsonplaceholder</span>
          </div>
        </div>
      </section>

      <Table
        columns={POSTS_COLUMNS}
        data={tableData}
        isLoading={isLoading}
        onRowClick={(row) => navigate(`/posts/${row.id}`)}
      />
    </main>
  );
}
